class Solution {
public:
    bool checkPalindromeFormation(string a, string b) {
        return check(a, b) || check(b, a);
    }

    bool check(string a, string b) {
        int n = a.size();
        for (int i = 0; i <= n / 2; i++) {
            if (isPalindrome(a, i, n - i) && isPalindrome(b, i, n - i)) {
                return true;
            }
        }
        return false;
    }

    bool isPalindrome(string s, int l, int r) {
        while (l < r) {
            if (s[l] != s[r]) {
                return false;
            }
            l++;
            r--;
        }
        return true;
    }
};
